def evaluate_traffic_impact(
    edges,
    node_signal_delay,
    base_blocked,
    queries
):
    # Build adjacency: for each u -> list of (v, lanes)
    adj = {}
    nodes = set()
    for e in edges:
        u = int(e["from"])
        v = int(e["to"])
        nodes.add(u); nodes.add(v)
        lanes = e.get("lanes", [])
        adj.setdefault(u, []).append((v, tuple((lane["mode"], int(lane["travel_time"]), int(lane["capacity"])) for lane in lanes)))
    # Normalize node_signal_delay and base_blocked
    signal = {int(k): int(v) for k,v in node_signal_delay.items()}
    base_block = {int(k): set(v) for k,v in base_blocked.items()}
    for n in nodes:
        signal.setdefault(n, 0)
        base_block.setdefault(n, set())
    # Working state copies
    current_block = {n: set(base_block[n]) for n in base_block}
    current_signal = dict(signal)
    results = []
    # Helper: compute shortest path with tie-breakers using Dijkstra with lexicographic via parent tracking
    def dijkstra(src: int, dst: int, blocked: Dict[int, set], signal_map: Dict[int,int]):
        # If src or dst blocked all modes? note block is per mode; node closure relevant when traversing edge if target node has no allowed mode for arriving lane
        # We'll consider an edge usable if there exists a lane whose mode is NOT blocked at both u and v? Problem says close all "road" lanes at a node: that restricts lanes at node; so an edge lane is usable if its mode is not blocked at source node and not blocked at target node.
        INF = 10**30
        dist = {}
        edges_count = {}
        parent = {}
        # For lexicographic tie-breaker, store path as tuple when needed; but reconstruct via parents with node id comparisons by pushing into heap (dist, edges, path_tuple, node)
        # To avoid storing full path in heap for large graphs, keep path tuples but limited: we will store path tuple up to current node. This increases memory but acceptable for correctness.
        heap = []
        start_path = (src,)
        heapq.heappush(heap, (0 + signal_map.get(src,0), 0, start_path, src))
        dist[src] = 0 + signal_map.get(src,0)
        edges_count[src] = 0
        parent[src] = None
        visited = {}
        while heap:
            total_cost, ecount, path_tuple, u = heapq.heappop(heap)
            if visited.get(u) is not None:
                # ensure same tuple tie-breaker
                prev = visited[u]
                if prev <= (total_cost, ecount, path_tuple):
                    continue
            visited[u] = (total_cost, ecount, path_tuple)
            if u == dst:
                # reconstruct path from path_tuple
                return total_cost, ecount, list(path_tuple)
            for (v, lanes) in adj.get(u, []):
                # determine best lane among lanes considering blocked modes
                best_travel = None
                modes_used = set()
                for mode, travel_time, capacity in lanes:
                    if mode in blocked.get(u, set()): 
                        continue
                    if mode in blocked.get(v, set()):
                        continue
                    # lane usable
                    if best_travel is None or travel_time < best_travel:
                        best_travel = travel_time
                if best_travel is None:
