                known = (dist.get(v, INF), edges_count.get(v, 10**12), None)
                # To compare lexicographically, we need previous path; we don't store so use parent reconstruction if necessary: but we have visited storing path_tuple for popped nodes; for unpopped nodes, we can store path in dist store as well.
                # Simpler: keep best_path_map storing tuple
